module multi_8bit
(
    input [7:0] A,
    input [7:0] B,
    output reg [15:0] product
);

reg [7:0] multiplicand;
reg [7:0] multiplier;
reg [15:0] partial_product;
reg [3:0] shift_count;

always @(*) begin
    multiplicand = A;
    multiplier = B;
    partial_product = 16'b0;
    shift_count = 4'b0;

    while (shift_count < 8) begin
        if (multiplier[0]) begin
            partial_product = partial_product + (multiplicand << shift_count);
        end
        multiplier = multiplier >> 1;
        shift_count = shift_count + 1;
    end

    product = partial_product;
end

endmodule
